import { useState, useEffect, useRef } from "react"; // ─── DATA ──────────────────────────────────────────────────────────────────── const PLACES = [ { id: "sinai-beach", name: "Sinai Beach", area: "Dahab, South Sinai", emoji: "🏖️", tag: "Beach", people: 14, replyAvg: 38, gradient: "linear-gradient(145deg, #1a6b6b 0%, #0d3d4a 100%)", accent: "#3ECFCF", prompts: [ "Is the water calm right now?", "How crowded is it?", "Any shade available?", "Is snorkeling gear available to rent?", "What's the vibe like today?", ], recentReplies: [ { q: "Is there parking nearby?", a: "Yes, right by the entrance. Pretty full though.", helpful: true, time: "4m ago" }, { q: "How's the water temperature?", a: "Perfect honestly, not too cold", helpful: true, time: "11m ago" }, ], // Photo palette for mocked live photo photoPalette: ["#7EC8D4","#A8DDE8","#5BA8B8","#3D8898","#2A6878","#B8EEF5","#4ABAC8"], photoLabel: "beach & water right now", }, { id: "sinai-camp", name: "Bedouin Star Camp", area: "Ras Abu Galum, Sinai", emoji: "⛺", tag: "Camp", people: 6, replyAvg: 72, gradient: "linear-gradient(145deg, #3d2b1a 0%, #1a1008 100%)", accent: "#E8A84C", prompts: [ "Is there space to camp tonight?", "How's the food situation?", "Do they have electricity?", "Is it safe to arrive after dark?", "How far is the nearest ATM?", ], recentReplies: [ { q: "Is it cold at night?", a: "Bring a layer, drops a lot after sunset", helpful: true, time: "22m ago" }, ], photoPalette: ["#3d2b1a","#C8A87A","#8A6A3A","#F0D8A8","#6A4A1A","#2A1A08","#E8C888"], photoLabel: "camp scene now", }, { id: "blue-hole", name: "Blue Hole", area: "Dahab, South Sinai", emoji: "🤿", tag: "Dive Site", people: 9, replyAvg: 55, gradient: "linear-gradient(145deg, #0a2a6e 0%, #061440 100%)", accent: "#5B9CF6", prompts: [ "How's visibility today?", "Is the site crowded?", "Any equipment rental on-site?", "Safe for beginner snorkelers?", "Current conditions?", ], recentReplies: [ { q: "Visibility?", a: "Visibility is insane today, like 20m+ easy", helpful: true, time: "8m ago" }, { q: "Crowded?", a: "Not bad, maybe 15 people total at the site", helpful: true, time: "31m ago" }, ], photoPalette: ["#0a2a6e","#1A4AB8","#2A5AC8","#0A1A5A","#3A7AE8","#B8D8F8","#0A3A9A"], photoLabel: "visibility from the surface", }, { id: "nuweiba-port", name: "Nuweiba Port", area: "Nuweiba, South Sinai", emoji: "⛴️", tag: "Transport", people: 23, replyAvg: 18, gradient: "linear-gradient(145deg, #2a2a4a 0%, #111128 100%)", accent: "#9F8DF5", prompts: [ "Is the Jordan ferry running today?", "How long is the queue?", "Are tickets available on-site?", "When does the next ferry leave?", ], recentReplies: [ { q: "Ferry running?", a: "Yes running, queue is maybe 1.5hrs", helpful: true, time: "2m ago" }, { q: "Tickets on site?", a: "Yes but bring cash, card didn't work for me", helpful: false, time: "19m ago" }, ], photoPalette: ["#2a2a4a","#4A4A8A","#6A6AAA","#1A1A3A","#8A8AC8","#C8C8F0","#3A3A6A"], photoLabel: "port & queue right now", }, ]; // ── RESPONDERS with trust metadata ──────────────────────────────────────────── // visits = times checked into this type of place on Instantip // rate = % of their replies marked helpful // badge = earned label // verified = manually reviewed for accuracy const RESPONDERS = [ { name: "Karim", initial: "K", accent: "#3ECFCF", visits: 34, rate: 97, badge: "Local guide", verified: true, bio: "Dahab local, dives here weekly" }, { name: "Nour", initial: "N", accent: "#F97AB8", visits: 12, rate: 91, badge: "Frequent visitor", verified: false, bio: "Visited 12× in the last 6 months" }, { name: "Omar", initial: "O", accent: "#7EC87E", visits: 61, rate: 99, badge: "Local guide", verified: true, bio: "Born in Dahab, knows every spot" }, { name: "Layla", initial: "L", accent: "#E8A84C", visits: 7, rate: 88, badge: "Visitor", verified: false, bio: "Traveling through South Sinai" }, { name: "Youssef", initial: "Y", accent: "#9F8DF5", visits: 19, rate: 94, badge: "Frequent visitor", verified: true, bio: "Based in Dahab, guides dive trips" }, ]; // Per-place scripted replies with optional photo trigger // Replies are keyed by a lowercase substring of the question so the answer // actually matches what was asked. Fall back to a place-level default for // freeform questions that don't match any known prompt. const SCRIPTED_REPLIES = { "sinai-beach": { default: { text: "Yeah it's nice here right now, pretty relaxed.", withPhoto: true }, prompts: [ { match: "calm", text: "Really calm today, barely any waves. Perfect for snorkeling.", withPhoto: true }, { match: "crowded", text: "Pretty quiet honestly, maybe 20 people spread out along the beach.", withPhoto: false }, { match: "shade", text: "There are some palm shelters on the left side as you come in.", withPhoto: false }, { match: "snorkeling", text: "Yes, a guy near the entrance rents gear — mask, fins, 50 EGP I think.", withPhoto: false }, { match: "vibe", text: "Super chill today. Mix of locals and backpackers, no loud music.", withPhoto: true }, { match: "vegan", text: "The beach café has a falafel wrap and a fruit plate, that's about it.", withPhoto: false }, { match: "food", text: "There's a small café — sandwiches, fruit, tea. Nothing fancy.", withPhoto: false }, ], }, "sinai-camp": { default: { text: "Yeah we're here, it's good. Ask me anything.", withPhoto: false }, prompts: [ { match: "space", text: "There's space, maybe 3 tents set up right now. Plenty of room.", withPhoto: false }, { match: "food", text: "They made tagine tonight. Tomorrow breakfast is included.", withPhoto: false }, { match: "vegan", text: "The cook can do a vegetable tagine, just ask when you arrive.", withPhoto: false }, { match: "electricity", text: "There's a solar panel for phone charging, no mains power.", withPhoto: false }, { match: "dark", text: "I arrived after sunset, it's fine — just have a headlamp for the path.", withPhoto: false }, { match: "atm", text: "Nearest ATM is back in Dahab town, about 45 min by pickup truck.", withPhoto: false }, { match: "cold", text: "Drops a lot after sunset, bring a layer. Days are warm though.", withPhoto: false }, ], }, "blue-hole": { default: { text: "Conditions are good today. Happy to help.", withPhoto: true }, prompts: [ { match: "visibility", text: "Visibility is excellent, easily 15–20m from the surface right now.", withPhoto: true }, { match: "crowded", text: "Not bad — maybe 15 divers total at the site, spread out.", withPhoto: false }, { match: "equipment", text: "There's a dive centre at the top, rentals available.", withPhoto: false }, { match: "rental", text: "Yes, gear rental at the dive centre — basic kit, reasonable prices.", withPhoto: false }, { match: "beginner", text: "The saddle is fine for snorkelers, but the hole itself is deep. Stick to the surface.", withPhoto: false }, { match: "current", text: "Very light current today, if any. Surface is calm.", withPhoto: true }, ], }, "nuweiba-port": { default: { text: "I'm here at the port now, what do you need to know?", withPhoto: false }, prompts: [ { match: "ferry", text: "Ferry is running today. Departure is usually around 3pm, confirm at the desk.", withPhoto: false }, { match: "queue", text: "Queue for boarding took us about 45 minutes this morning.", withPhoto: false }, { match: "ticket", text: "Yes, tickets at the counter on arrival. Bring cash — card didn't work for me.", withPhoto: false }, { match: "next", text: "Next ferry is this afternoon, around 3pm. Check the board when you arrive.", withPhoto: false }, { match: "running", text: "Yes, it's running today. I just checked in.", withPhoto: false }, ], }, }; // Returns the best scripted reply for a given place + question text. // Matches on a lowercase keyword in the question; falls back to place default. function getScriptedReply(placeId, question) { const block = SCRIPTED_REPLIES[placeId]; if (!block) return { text: "Looks good from where I'm standing.", withPhoto: false }; const q = (question || "").toLowerCase(); const match = block.prompts && block.prompts.find(p => q.includes(p.match)); return match || block.default; } // Probability of getting a reply in auto demo mode (0–1). // 0.7 = 70% chance of reply, 30% chance of no answer. const DEMO_REPLY_PROBABILITY = 0.7; // Delay before auto outcome fires in demo mode. const DEMO_AUTO_DELAY = 5000; // ─── SHARED COMPONENTS ──────────────────────────────────────────────────────── function LiveDot({ color, size = 8 }) { return ( <span style={{ width: size, height: size, borderRadius: "50%", background: color || "#4ADE80", display: "inline-block", flexShrink: 0, animation: "livepulse 2s ease-in-out infinite", }} /> ); } // Trust badge row shown in chat header and responder card function TrustMeta({ responder, compact }) { return compact ? ( <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}> <span style={{ fontSize: 10, fontFamily: "'DM Mono', monospace", background: responder.verified ? "rgba(74,222,128,0.12)" : "rgba(255,255,255,0.06)", color: responder.verified ? "#4ADE80" : "#888898", border: 1px solid ${responder.verified ? "#4ADE8033" : "#2A2A38"}, borderRadius: 6, padding: "2px 7px", display: "inline-flex", alignItems: "center", gap: 4, }}> {responder.verified ? "✓ verified" : responder.badge} </span> <span style={{ fontSize: 10, color: "#555570", fontFamily: "'DM Mono', monospace" }}> {responder.rate}% helpful · {responder.visits} visits </span> </div> ) : ( <div style={{ background: "#15151E", border: "1px solid #22222F", borderRadius: 14, padding: "12px 14px", marginBottom: 14, }}> <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}> <div style={{ width: 38, height: 38, borderRadius: "50%", background: responder.accent + "22", border: 2px solid ${responder.accent}55, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontWeight: 700, color: responder.accent, fontFamily: "'Fraunces', serif", flexShrink: 0, }}>{responder.initial}</div> <div> <div style={{ fontSize: 14, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> {responder.name} {responder.verified && ( <span style={{ marginLeft: 6, fontSize: 10, background: "rgba(74,222,128,0.12)", color: "#4ADE80", border: "1px solid #4ADE8033", borderRadius: 5, padding: "1px 6px", fontFamily: "'DM Mono', monospace", verticalAlign: "middle", }}>✓ verified</span> )} </div> <div style={{ fontSize: 11, color: "#555570", fontFamily: "'DM Mono', monospace", marginTop: 1 }}> {responder.bio} </div> </div> </div> <div style={{ display: "flex", gap: 8 }}> {[ { label: "helpful rate", value: responder.rate + "%" }, { label: "visits here", value: responder.visits }, { label: "badge", value: responder.badge }, ].map(m => ( <div key={m.label} style={{ flex: 1, background: "#0C0C0F", borderRadius: 10, padding: "8px 10px", }}> <div style={{ fontSize: 13, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}>{m.value}</div> <div style={{ fontSize: 10, color: "#444456", fontFamily: "'DM Mono', monospace", marginTop: 1 }}>{m.label}</div> </div> ))} </div> </div> ); } // Mocked live photo — generated from palette, no real image needed function LivePhoto({ place, caption }) { const p = place.photoPalette; const id = place.id; return ( <div style={{ borderRadius: 14, overflow: "hidden", marginTop: 6, border: "1px solid #22222F", animation: "fadein 0.4s ease", }}> {/* Generated scene */} <div style={{ position: "relative", height: 140, background: p[0] }}> {/* Sky / background layer */} <div style={{ position: "absolute", inset: 0, background: linear-gradient(180deg, ${p[1]} 0%, ${p[0]} 60%, ${p[2]} 100%), }} /> {/* Horizon detail */} <div style={{ position: "absolute", bottom: "35%", left: 0, right: 0, height: 2, background: p[3] + "88", }} /> {/* Water ripples / terrain lines */} {[0,1,2,3].map(i => ( <div key={i} style={{ position: "absolute", bottom: ${8 + i * 9}%, left: ${5 + i * 3}%, right: ${3 + i * 2}%, height: 1.5, background: p[4 % p.length] + (i % 2 === 0 ? "66" : "33"), borderRadius: 2, }} /> ))} {/* Sun / moon glow */} <div style={{ position: "absolute", top: "18%", right: "18%", width: 22, height: 22, borderRadius: "50%", background: p[5 % p.length] || "#fff", boxShadow: 0 0 20px 8px ${p[5 % p.length] || "#fff"}55, opacity: 0.85, }} /> {/* Noise grain overlay */} <div style={{ position: "absolute", inset: 0, background: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 128 128' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.08'/%3E%3C/svg%3E\")", mixBlendMode: "overlay", }} /> {/* LIVE badge */} <div style={{ position: "absolute", top: 10, left: 10, display: "flex", alignItems: "center", gap: 5, background: "rgba(0,0,0,0.55)", backdropFilter: "blur(4px)", borderRadius: 20, padding: "4px 9px", }}> <span style={{ width: 6, height: 6, borderRadius: "50%", background: "#F87171", display: "inline-block", animation: "livepulse 1.5s ease-in-out infinite", }} /> <span style={{ fontSize: 10, color: "#fff", fontFamily: "'DM Mono', monospace", fontWeight: 500, letterSpacing: "0.08em" }}> LIVE </span> </div> {/* Timestamp */} <div style={{ position: "absolute", bottom: 8, right: 10, fontSize: 10, color: "rgba(255,255,255,0.7)", fontFamily: "'DM Mono', monospace", }}>just now</div> </div> {/* Caption strip */} <div style={{ padding: "8px 12px", background: "#18181F", display: "flex", alignItems: "center", gap: 7, }}> <span style={{ fontSize: 12 }}>📷</span> <span style={{ fontSize: 11, color: "#888898", fontFamily: "'DM Mono', monospace" }}> {caption || place.photoLabel} </span> </div> </div> ); } // ─── SCREEN: PLACE LIST ────────────────────────────────────────────────────── function PlaceListScreen({ onSelect, onIAmHere }) { const [search, setSearch] = useState(""); const filtered = PLACES.filter(p => p.name.toLowerCase().includes(search.toLowerCase()) || p.area.toLowerCase().includes(search.toLowerCase()) ); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> <div style={{ padding: "28px 20px 16px", flexShrink: 0 }}> <div style={{ marginBottom: 20 }}> <div style={{ fontSize: 11, color: "#555570", fontFamily: "'DM Mono', monospace", letterSpacing: "0.14em", textTransform: "uppercase", marginBottom: 4, }}>instantip</div> <div style={{ fontSize: 22, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", lineHeight: 1.2 }}> Ask someone<br />who's there <em style={{ color: "#F5A623", fontStyle: "italic" }}>now.</em> </div> </div> <div style={{ display: "flex", alignItems: "center", gap: 10, background: "#18181F", border: "1px solid #2A2A38", borderRadius: 14, padding: "11px 14px", }}> <span style={{ color: "#444456", fontSize: 15 }}>⌕</span> <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search places..." style={{ background: "none", border: "none", outline: "none", color: "#D0CCC4", fontSize: 14, fontFamily: "'DM Sans', sans-serif", flex: 1, caretColor: "#F5A623", }} /> </div> </div> <div style={{ padding: "0 20px 10px", fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", letterSpacing: "0.1em", textTransform: "uppercase", flexShrink: 0, display: "flex", alignItems: "center", gap: 7, }}> <LiveDot color="#4ADE80" size={6} /> Places with people now </div> <div style={{ flex: 1, overflowY: "auto", padding: "0 20px 24px", display: "flex", flexDirection: "column", gap: 12 }}> {filtered.map((place, i) => ( <button key={place.id} onClick={() => onSelect(place)} style={{ background: place.gradient, border: "1px solid rgba(255,255,255,0.07)", borderRadius: 20, padding: "20px", cursor: "pointer", textAlign: "left", animation: fadein 0.3s ease ${i * 0.07}s both, position: "relative", overflow: "hidden", }}> <div style={{ position: "absolute", inset: 0, borderRadius: 20, background: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.04'/%3E%3C/svg%3E\")", pointerEvents: "none", }} /> <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}> <div> <div style={{ fontSize: 22, marginBottom: 6 }}>{place.emoji}</div> <div style={{ fontSize: 17, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> {place.name} </div> <div style={{ fontSize: 12, color: "rgba(240,237,232,0.5)", fontFamily: "'DM Mono', monospace", marginTop: 2 }}> {place.area} </div> </div> <span style={{ display: "inline-flex", alignItems: "center", padding: "3px 9px", borderRadius: 20, fontSize: 11, color: "rgba(240,237,232,0.7)", background: "rgba(0,0,0,0.3)", fontFamily: "'DM Mono', monospace", }}>{place.tag}</span> </div> <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}> <div style={{ display: "flex", alignItems: "center", gap: 7 }}> <LiveDot color={place.accent} size={7} /> <span style={{ fontSize: 12, color: place.accent, fontFamily: "'DM Mono', monospace", fontWeight: 500 }}> {place.people} people here </span> </div> <div style={{ fontSize: 11, color: "rgba(240,237,232,0.4)", fontFamily: "'DM Mono', monospace" }}> ~{place.replyAvg}s reply </div> </div> </button> ))} </div> {/* Responder entry — opens place picker */} <div style={{ padding: "10px 20px 18px", flexShrink: 0, borderTop: "1px solid #0E0E14", }}> <button onClick={() => onIAmHere(null)} style={{ width: "100%", padding: "10px 16px", background: "transparent", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 7, }}> <LiveDot color="#333345" size={5} /> <span style={{ fontSize: 11, color: "#2A2A3A", fontFamily: "'DM Mono', monospace" }}> I'm at one of these places </span> </button> </div> </div> ); } // ─── SCREEN: PLACE DETAIL ──────────────────────────────────────────────────── function PlaceDetailScreen({ place, onAsk, onBack }) { return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> <div style={{ background: place.gradient, padding: "24px 20px 28px", flexShrink: 0, position: "relative", overflow: "hidden", }}> <div style={{ position: "absolute", inset: 0, background: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.05'/%3E%3C/svg%3E\")", pointerEvents: "none", }} /> <button onClick={onBack} style={{ background: "rgba(0,0,0,0.3)", border: "none", color: "#D0CCC4", borderRadius: 12, padding: "7px 14px", cursor: "pointer", fontSize: 13, fontFamily: "'DM Mono', monospace", marginBottom: 20, }}>← back</button> <div style={{ fontSize: 32, marginBottom: 8 }}>{place.emoji}</div> <div style={{ fontSize: 24, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 4 }}> {place.name} </div> <div style={{ fontSize: 12, color: "rgba(240,237,232,0.5)", fontFamily: "'DM Mono', monospace", marginBottom: 16 }}> {place.area} </div> <div style={{ display: "flex", gap: 10, alignItems: "center" }}> <div style={{ display: "flex", alignItems: "center", gap: 7, background: "rgba(0,0,0,0.35)", borderRadius: 20, padding: "6px 12px", }}> <LiveDot color={place.accent} size={8} /> <span style={{ fontSize: 13, color: place.accent, fontFamily: "'DM Mono', monospace", fontWeight: 600 }}> {place.people} here now </span> </div> <div style={{ background: "rgba(0,0,0,0.25)", borderRadius: 20, padding: "6px 12px", fontSize: 12, color: "rgba(240,237,232,0.55)", fontFamily: "'DM Mono', monospace", }}> avg reply ~{place.replyAvg}s </div> </div> </div> <div style={{ flex: 1, overflowY: "auto", padding: "20px 20px 8px" }}> <div style={{ fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12, }}>Recent answers from people there</div> <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 24 }}> {place.recentReplies.map((r, i) => ( <div key={i} style={{ background: "#15151E", border: "1px solid #22222F", borderRadius: 16, padding: "14px", animation: fadein 0.3s ease ${i * 0.1}s both, }}> <div style={{ fontSize: 12, color: "#888898", fontFamily: "'DM Mono', monospace", marginBottom: 6 }}> Q: {r.q} </div> <div style={{ fontSize: 14, color: "#D0CCC4", fontFamily: "'DM Sans', sans-serif", lineHeight: 1.45, marginBottom: 10 }}> "{r.a}" </div> <span style={{ fontSize: 11, fontFamily: "'DM Mono', monospace", color: r.helpful ? "#4ADE80" : "#F87171", }}> {r.helpful ? "✓ helpful" : "✗ not helpful"} · {r.time} </span> </div> ))} </div> <div style={{ fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12, }}>Common questions</div> <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 8 }}> {place.prompts.slice(0, 3).map((p, i) => ( <button key={i} onClick={() => onAsk(p)} style={{ background: "#18181F", border: "1px solid #2A2A38", borderRadius: 12, padding: "11px 14px", color: "#B0ACC4", fontSize: 14, fontFamily: "'DM Sans', sans-serif", cursor: "pointer", textAlign: "left", transition: "all 0.15s", animation: fadein 0.3s ease ${i * 0.08}s both, }} onMouseEnter={e => { e.currentTarget.style.borderColor = place.accent + "66"; e.currentTarget.style.color = "#F0EDE8"; }} onMouseLeave={e => { e.currentTarget.style.borderColor = "#2A2A38"; e.currentTarget.style.color = "#B0ACC4"; }} > {p} </button> ))} </div> </div> <div style={{ padding: "12px 20px 28px", flexShrink: 0 }}> <button onClick={() => onAsk(null)} style={{ width: "100%", padding: "16px", background: place.accent, border: "none", borderRadius: 16, color: "#0C0C0F", fontSize: 16, fontWeight: 700, fontFamily: "'Fraunces', serif", cursor: "pointer", boxShadow: 0 8px 32px ${place.accent}44, transition: "all 0.2s", }} onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-1px)"; }} onMouseLeave={e => { e.currentTarget.style.transform = "translateY(0)"; }} > Ask someone there → </button> </div> </div> ); } // ─── SCREEN: ASK FLOW ──────────────────────────────────────────────────────── function AskScreen({ place, prefill, onSend, onBack }) { const [question, setQuestion] = useState(prefill || ""); const textRef = useRef(null); useEffect(() => { textRef.current && textRef.current.focus(); }, []); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> <div style={{ padding: "24px 20px 16px", flexShrink: 0 }}> <button onClick={onBack} style={{ background: "rgba(255,255,255,0.06)", border: "none", color: "#888898", borderRadius: 12, padding: "7px 14px", cursor: "pointer", fontSize: 13, fontFamily: "'DM Mono', monospace", marginBottom: 24, }}>← back</button> <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 20 }}> <div style={{ width: 40, height: 40, borderRadius: 12, background: place.gradient, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, border: "1px solid rgba(255,255,255,0.08)", flexShrink: 0, }}>{place.emoji}</div> <div> <div style={{ fontSize: 15, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}>{place.name}</div> <div style={{ display: "flex", alignItems: "center", gap: 5, marginTop: 2 }}> <LiveDot color={place.accent} size={6} /> <span style={{ fontSize: 11, color: place.accent, fontFamily: "'DM Mono', monospace" }}>{place.people} people here</span> </div> </div> </div> <div style={{ fontSize: 18, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 4 }}> What do you want to know? </div> <div style={{ fontSize: 13, color: "#555570", fontFamily: "'DM Sans', sans-serif", marginBottom: 20 }}> A real person there will reply — usually within a minute. </div> <textarea ref={textRef} value={question} onChange={e => setQuestion(e.target.value.slice(0, 160))} placeholder="Type your question..." rows={3} style={{ width: "100%", background: "#15151E", border: "1.5px solid #2A2A38", borderRadius: 16, padding: "14px 16px", color: "#F0EDE8", fontSize: 15, fontFamily: "'DM Sans', sans-serif", outline: "none", resize: "none", lineHeight: 1.5, caretColor: place.accent, boxSizing: "border-box", }} onFocus={e => { e.target.style.borderColor = place.accent + "88"; }} onBlur={e => { e.target.style.borderColor = "#2A2A38"; }} /> <div style={{ fontSize: 11, color: "#333345", fontFamily: "'DM Mono', monospace", marginTop: 6, textAlign: "right" }}> {question.length}/160 </div> </div> <div style={{ flex: 1, overflowY: "auto", padding: "0 20px" }}> <div style={{ fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 10 }}> Or pick a question </div> <div style={{ display: "flex", flexDirection: "column", gap: 8 }}> {place.prompts.map((p, i) => ( <button key={i} onClick={() => setQuestion(p)} style={{ background: question === p ? "#1E1E2E" : "#13131A", border: 1px solid ${question === p ? place.accent + "66" : "#1E1E2A"}, borderRadius: 12, padding: "10px 14px", color: question === p ? "#F0EDE8" : "#7A7890", fontSize: 13, fontFamily: "'DM Sans', sans-serif", cursor: "pointer", textAlign: "left", transition: "all 0.15s", }}> {p} </button> ))} </div> </div> <div style={{ padding: "16px 20px 28px", flexShrink: 0 }}> <button onClick={() => question.trim() && onSend(question.trim())} disabled={!question.trim()} style={{ width: "100%", padding: "15px", background: question.trim() ? place.accent : "#1E1E2A", border: "none", borderRadius: 16, color: question.trim() ? "#0C0C0F" : "#444456", fontSize: 15, fontWeight: 700, fontFamily: "'Fraunces', serif", cursor: question.trim() ? "pointer" : "default", transition: "all 0.2s", }} > Send question </button> </div> </div> ); } // ─── SCREEN: WAITING ───────────────────────────────────────────────────────── function WaitingScreen({ place, question, onReply, onNoAnswer }) { const [seconds, setSeconds] = useState(0); // "auto" picks one outcome upfront by probability, then fires a single timer. // Manual buttons bypass the timer entirely — instant, no state needed. const [demoMode, setDemoMode] = useState("auto"); // "auto" | "reply" | "noanswer" const responderRef = useRef(RESPONDERS[Math.floor(Math.random() * RESPONDERS.length)]); // Resolve reply at render time so it matches the actual question asked. const scriptedReply = useRef(getScriptedReply(place.id, question)).current; const autoTimerRef = useRef(null); function clearAuto() { if (autoTimerRef.current) { clearTimeout(autoTimerRef.current); autoTimerRef.current = null; } } function fireReply() { clearAuto(); onReply(responderRef.current, scriptedReply.text, scriptedReply.withPhoto); } function fireNoAnswer() { clearAuto(); onNoAnswer(); } // Re-runs whenever demoMode changes (user switches the selector). useEffect(() => { const tick = setInterval(() => setSeconds(s => s + 1), 1000); if (demoMode === "auto") { // Choose ONE outcome now — no competing timers. // DEMO_REPLY_PROBABILITY = 0.7 → 70% reply, 30% no-answer. const willReply = Math.random() < DEMO_REPLY_PROBABILITY; autoTimerRef.current = setTimeout( willReply ? fireReply : fireNoAnswer, DEMO_AUTO_DELAY, ); } // "reply" / "noanswer" modes: outcome fires when user clicks the button below. return () => { clearInterval(tick); clearAuto(); }; }, [demoMode]); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F", alignItems: "center", justifyContent: "center", padding: "40px 28px", textAlign: "center", position: "relative", }}> <div style={{ position: "relative", width: 100, height: 100, marginBottom: 32 }}> {[0, 1, 2].map(i => ( <div key={i} style={{ position: "absolute", inset: ${i * 14}%, borderRadius: "50%", border: 1.5px solid ${place.accent}, opacity: 0, animation: ring-out 2.4s ease-out ${i * 0.6}s infinite, }} /> ))} <div style={{ position: "absolute", inset: "30%", borderRadius: "50%", background: place.accent + "22", border: 2px solid ${place.accent}, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, }}>{place.emoji}</div> </div> <div style={{ fontSize: 20, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 10 }}> Reaching someone at<br />{place.name}… </div> <div style={{ background: "#15151E", border: "1px solid #22222F", borderRadius: 14, padding: "12px 18px", marginBottom: 24, maxWidth: 280, }}> <div style={{ fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", marginBottom: 4 }}>your question</div> <div style={{ fontSize: 14, color: "#B0ACC4", fontFamily: "'DM Sans', sans-serif", fontStyle: "italic" }}> "{question}" </div> </div> <div style={{ display: "flex", alignItems: "center", gap: 8 }}> {[0, 0.2, 0.4].map((d, i) => ( <span key={i} style={{ width: 7, height: 7, borderRadius: "50%", background: place.accent + "88", display: "inline-block", animation: typingdot 1.1s ease-in-out ${d}s infinite, }} /> ))} </div> <div style={{ marginTop: 12, fontSize: 12, color: "#333345", fontFamily: "'DM Mono', monospace" }}> {seconds}s · avg reply ~{place.replyAvg}s </div> {/* ── Demo controls ── clearly labelled, visually subordinate ── */} <div style={{ position: "absolute", bottom: 18, left: 0, right: 0, display: "flex", flexDirection: "column", alignItems: "center", gap: 7, }}> <div style={{ fontSize: 9, color: "#1E1E28", fontFamily: "'DM Mono', monospace", letterSpacing: "0.14em", textTransform: "uppercase" }}> demo </div> {/* Mode selector — three small pills */} <div style={{ display: "flex", gap: 4, marginBottom: 2 }}> {[ { key: "auto", label: "Auto" }, { key: "reply", label: "Reply" }, { key: "noanswer", label: "No answer" }, ].map(({ key, label }) => ( <button key={key} onClick={() => setDemoMode(key)} style={{ padding: "4px 10px", borderRadius: 7, background: demoMode === key ? "#22222F" : "transparent", border: 1px solid ${demoMode === key ? "#33334A" : "#18181F"}, color: demoMode === key ? "#888898" : "#2A2A3A", fontSize: 10, fontFamily: "'DM Mono', monospace", cursor: "pointer", transition: "all 0.15s", }}>{label}</button> ))} </div> {/* Fire button — only shown in manual modes */} {demoMode === "reply" && ( <button onClick={fireReply} style={{ padding: "5px 14px", borderRadius: 8, background: "#0D2B1A", border: "1px solid #1A4A2A", color: "#4ADE80", fontSize: 11, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}>→ Fire reply now</button> )} {demoMode === "noanswer" && ( <button onClick={fireNoAnswer} style={{ padding: "5px 14px", borderRadius: 8, background: "#2B0D0D", border: "1px solid #4A1A1A", color: "#F87171", fontSize: 11, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}>→ Fire no answer now</button> )} {demoMode === "auto" && ( <div style={{ fontSize: 10, color: "#1E1E28", fontFamily: "'DM Mono', monospace" }}> {Math.round(DEMO_REPLY_PROBABILITY * 100)}% reply · {Math.round((1 - DEMO_REPLY_PROBABILITY) * 100)}% no answer · fires in ~{DEMO_AUTO_DELAY / 1000}s </div> )} </div> </div> ); } // ─── SCREEN: NO ANSWER FALLBACK ─────────────────────────────────────────────── function NoAnswerScreen({ place, question, onRetry, onLeave }) { return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F", alignItems: "center", justifyContent: "center", padding: "40px 28px", textAlign: "center", }}> <div style={{ fontSize: 44, marginBottom: 20, animation: "fadein 0.4s ease", }}>🕐</div> <div style={{ fontSize: 20, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 8 }}> No one replied yet </div> <div style={{ fontSize: 14, color: "#555570", fontFamily: "'DM Sans', sans-serif", lineHeight: 1.6, marginBottom: 28, maxWidth: 270 }}> People at {place.name} may be away from their phones right now. Your question has been queued — we'll notify you when someone answers. </div> {/* Question reminder */} <div style={{ background: "#15151E", border: "1px solid #22222F", borderRadius: 14, padding: "12px 18px", marginBottom: 28, width: "100%", maxWidth: 300, }}> <div style={{ fontSize: 11, color: "#444456", fontFamily: "'DM Mono', monospace", marginBottom: 4 }}>queued question</div> <div style={{ fontSize: 14, color: "#B0ACC4", fontFamily: "'DM Sans', sans-serif", fontStyle: "italic" }}> "{question}" </div> </div> {/* Context pill — how many are actually there */} <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 32, background: "#18181F", borderRadius: 20, padding: "6px 14px", border: "1px solid #22222F", }}> <LiveDot color={place.accent} size={7} /> <span style={{ fontSize: 12, color: "#888898", fontFamily: "'DM Mono', monospace" }}> {place.people} people at {place.name} · question sent to all </span> </div> <div style={{ display: "flex", flexDirection: "column", gap: 10, width: "100%", maxWidth: 300 }}> <button onClick={onRetry} style={{ width: "100%", padding: "13px", background: place.accent, border: "none", borderRadius: 14, color: "#0C0C0F", fontSize: 14, fontWeight: 700, fontFamily: "'Fraunces', serif", cursor: "pointer", boxShadow: 0 6px 24px ${place.accent}33, }}> Try asking again </button> <button onClick={onLeave} style={{ width: "100%", padding: "13px", background: "#18181F", border: "1px solid #2A2A38", borderRadius: 14, color: "#555570", fontSize: 13, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}> Ask about a different place </button> </div> {/* Fine print */} <div style={{ marginTop: 24, fontSize: 10, color: "#222230", fontFamily: "'DM Mono', monospace", lineHeight: 1.7 }}> Unanswered questions are automatically removed after 2 hours.<br /> You won't be charged for unanswered requests. </div> </div> ); } // ─── SCREEN: PRIVATE CHAT ──────────────────────────────────────────────────── function ChatScreen({ place, question, responder, initialReply, withPhoto, onDone }) { const [messages, setMessages] = useState(() => { const base = [ { id: 1, from: "me", text: question }, { id: 2, from: "them", text: initialReply }, ]; if (withPhoto) base.push({ id: 3, from: "them", type: "photo" }); return base; }); const [input, setInput] = useState(""); const [rated, setRated] = useState(null); const [showReport, setShowReport] = useState(false); const [reported, setReported] = useState(false); const [showTrust, setShowTrust] = useState(false); const [followupTyping, setFollowupTyping] = useState(false); const bottomRef = useRef(null); const inputRef = useRef(null); useEffect(() => { bottomRef.current && bottomRef.current.scrollIntoView({ behavior: "smooth" }); }, [messages, followupTyping]); function send() { const text = input.trim(); if (!text) return; setMessages(prev => [...prev, { id: Date.now(), from: "me", text }]); setInput(""); setFollowupTyping(true); setTimeout(() => { setFollowupTyping(false); const followups = [ "Yeah for sure, happy to help!", "Good question — I'd say it depends on the time of day.", "Honestly it's been great today, you should come.", "Not sure about that one, but I can check.", ]; setMessages(prev => [...prev, { id: Date.now() + 1, from: "them", text: followups[Math.floor(Math.random() * followups.length)], }]); }, 2000 + text.length * 25); } if (showReport && !reported) { return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F", padding: "32px 24px" }}> <button onClick={() => setShowReport(false)} style={{ background: "none", border: "none", color: "#555570", fontFamily: "'DM Mono', monospace", fontSize: 13, cursor: "pointer", textAlign: "left", marginBottom: 28, }}>← cancel</button> <div style={{ fontSize: 20, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 8 }}> Report or Block </div> <div style={{ fontSize: 14, color: "#555570", fontFamily: "'DM Sans', sans-serif", marginBottom: 28, lineHeight: 1.5 }}> Help keep Instantip safe. Select a reason: </div> {["Inappropriate content", "Spam or fake information", "Harassment", "Other"].map(reason => ( <button key={reason} onClick={() => { setReported(true); setShowReport(false); }} style={{ background: "#15151E", border: "1px solid #22222F", borderRadius: 14, padding: "14px 16px", marginBottom: 10, color: "#C0BCD4", fontSize: 14, fontFamily: "'DM Sans', sans-serif", cursor: "pointer", textAlign: "left", transition: "all 0.15s", }} onMouseEnter={e => { e.currentTarget.style.borderColor = "#F87171"; e.currentTarget.style.color = "#F87171"; }} onMouseLeave={e => { e.currentTarget.style.borderColor = "#22222F"; e.currentTarget.style.color = "#C0BCD4"; }} >{reason}</button> ))} </div> ); } return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> {/* Header with trust metadata */} <div style={{ padding: "14px 18px 0", borderBottom: "1px solid #18181F", flexShrink: 0, background: "#0E0E14", }}> <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingBottom: 12 }}> <button onClick={() => setShowTrust(t => !t)} style={{ display: "flex", alignItems: "center", gap: 10, background: "none", border: "none", cursor: "pointer", padding: 0, textAlign: "left", }}> <div style={{ width: 36, height: 36, borderRadius: "50%", background: responder.accent + "22", border: 2px solid ${responder.accent}55, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14, fontWeight: 700, color: responder.accent, fontFamily: "'Fraunces', serif", flexShrink: 0, }}>{responder.initial}</div> <div style={{ textAlign: "left" }}> <div style={{ display: "flex", alignItems: "center", gap: 6 }}> <span style={{ fontSize: 14, fontWeight: 600, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> {responder.name} </span> {responder.verified && ( <span style={{ fontSize: 9, background: "rgba(74,222,128,0.12)", color: "#4ADE80", border: "1px solid #4ADE8033", borderRadius: 4, padding: "1px 5px", fontFamily: "'DM Mono', monospace", }}>✓</span> )} </div> {/* Compact trust meta inline */} <TrustMeta responder={responder} compact /> </div> </button> <button onClick={() => setShowReport(true)} style={{ background: "none", border: "none", color: "#333345", fontSize: 18, cursor: "pointer", padding: "4px 8px", }}>⋯</button> </div> {/* Expandable full trust card */} {showTrust && ( <div style={{ paddingBottom: 12, animation: "fadein 0.2s ease" }}> <TrustMeta responder={responder} compact={false} /> </div> )} </div> {/* Messages */} <div style={{ flex: 1, overflowY: "auto", padding: "16px 18px", display: "flex", flexDirection: "column", gap: 14 }}> {reported && ( <div style={{ background: "#1A1010", border: "1px solid #3A1A1A", borderRadius: 12, padding: "10px 14px", fontSize: 12, color: "#F87171", fontFamily: "'DM Mono', monospace", textAlign: "center", }}>✓ Reported. Thanks for keeping Instantip safe.</div> )} {messages.map(msg => { const isMe = msg.from === "me"; if (msg.type === "photo") { return ( <div key={msg.id} style={{ display: "flex", gap: 9, alignItems: "flex-end", animation: "fadein 0.3s ease" }}> <div style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, background: responder.accent + "22", border: 1.5px solid ${responder.accent}55, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: responder.accent, fontFamily: "'Fraunces', serif", }}>{responder.initial}</div> <div style={{ maxWidth: "75%" }}> <LivePhoto place={place} /> </div> </div> ); } return ( <div key={msg.id} style={{ display: "flex", flexDirection: isMe ? "row-reverse" : "row", gap: 9, alignItems: "flex-end", animation: "fadein 0.25s ease", }}> {!isMe && ( <div style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, background: responder.accent + "22", border: 1.5px solid ${responder.accent}55, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: responder.accent, fontFamily: "'Fraunces', serif", }}>{responder.initial}</div> )} <div style={{ maxWidth: "75%", background: isMe ? place.accent : "#18181F", color: isMe ? "#0C0C0F" : "#D0CCC4", padding: "10px 14px", borderRadius: isMe ? "16px 4px 16px 16px" : "4px 16px 16px 16px", fontSize: 14, lineHeight: 1.5, fontFamily: "'DM Sans', sans-serif", border: isMe ? "none" : "1px solid #22222F", fontWeight: isMe ? 500 : 400, }}>{msg.text}</div> </div> ); })} {followupTyping && ( <div style={{ display: "flex", gap: 9, alignItems: "flex-end", animation: "fadein 0.2s ease" }}> <div style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, background: responder.accent + "22", border: 1.5px solid ${responder.accent}55, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: responder.accent, fontFamily: "'Fraunces', serif", }}>{responder.initial}</div> <div style={{ background: "#18181F", border: "1px solid #22222F", borderRadius: "4px 16px 16px 16px", padding: "12px 16px", display: "flex", gap: 5, alignItems: "center", }}> {[0, 0.18, 0.36].map((d, i) => ( <span key={i} style={{ width: 5, height: 5, borderRadius: "50%", background: "#444456", display: "inline-block", animation: typingdot 1.1s ease-in-out ${d}s infinite, }} /> ))} </div> </div> )} <div ref={bottomRef} /> </div> {/* Rate / follow-up */} {!rated ? ( <div style={{ padding: "12px 18px 24px", borderTop: "1px solid #18181F", background: "#0E0E14", flexShrink: 0 }}> <div style={{ display: "flex", gap: 8, alignItems: "flex-end", marginBottom: 10 }}> <input ref={inputRef} value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => { if (e.key === "Enter") send(); }} placeholder="Follow-up question..." style={{ flex: 1, background: "#15151E", border: "1px solid #2A2A38", borderRadius: 12, padding: "10px 14px", color: "#D0CCC4", fontSize: 14, fontFamily: "'DM Sans', sans-serif", outline: "none", caretColor: place.accent, }} onFocus={e => { e.target.style.borderColor = place.accent + "66"; }} onBlur={e => { e.target.style.borderColor = "#2A2A38"; }} /> <button onClick={send} disabled={!input.trim()} style={{ width: 40, height: 40, borderRadius: 12, flexShrink: 0, background: input.trim() ? place.accent : "#1E1E2A", border: "none", cursor: input.trim() ? "pointer" : "default", color: input.trim() ? "#0C0C0F" : "#333345", fontSize: 16, transition: "all 0.2s", }}>↑</button> </div> <div style={{ display: "flex", gap: 8, }}> <button onClick={() => setRated("helpful")} style={{ flex: 1, padding: "9px", background: "#0D2B1A", border: "1px solid #1A4A2A", borderRadius: 11, color: "#4ADE80", fontSize: 13, cursor: "pointer", fontFamily: "'DM Mono', monospace", }}>✓ Helpful</button> <button onClick={() => setRated("not")} style={{ flex: 1, padding: "9px", background: "#2B0D0D", border: "1px solid #4A1A1A", borderRadius: 11, color: "#F87171", fontSize: 13, cursor: "pointer", fontFamily: "'DM Mono', monospace", }}>✗ Not helpful</button> </div> </div> ) : ( <div style={{ padding: "14px 18px 26px", borderTop: "1px solid #18181F", background: "#0E0E14", flexShrink: 0 }}> <div style={{ background: rated === "helpful" ? "#0D2B1A" : "#2B0D0D", border: 1px solid ${rated === "helpful" ? "#1A4A2A" : "#4A1A1A"}, borderRadius: 12, padding: "11px", textAlign: "center", color: rated === "helpful" ? "#4ADE80" : "#F87171", fontSize: 12, fontFamily: "'DM Mono', monospace", marginBottom: 10, }}> {rated === "helpful" ? ✓ Marked helpful — this improves ${responder.name}'s trust score. : "✗ Got it — we'll factor this into rankings."} </div> <button onClick={onDone} style={{ width: "100%", padding: "12px", background: "#18181F", border: "1px solid #2A2A38", borderRadius: 13, color: "#888898", fontSize: 13, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}>← Ask about another place</button> </div> )} </div> ); } // ═══════════════════════════════════════════════════════════════════════════════ // RESPONDER FLOW — three screens, zero chat-app feeling // // Design principles applied: // 1. Status screen = one toggle + place context. Nothing else. // 2. Incoming = question fills the space. Quick replies ARE the screen. // Type/photo are inline expansions, not separate navigations. // 3. Confirmation = 2 lines, auto-dismisses. Not a reward screen. // ═══════════════════════════════════════════════════════════════════════════════ const INCOMING_REQUESTS = [ { id: "r1", q: "Is the water calm enough for snorkeling right now?", context: "Family · nearby" }, { id: "r2", q: "How crowded is it today?", context: "Solo traveler" }, { id: "r3", q: "Is there shade available on the beach?", context: "Traveler nearby" }, { id: "r4", q: "Is snorkeling gear available to rent here?", context: "First-time visitor" }, ]; // The four quick replies. These ARE the answer for most location questions. // Colors signal valence clearly — green yes, yellow partial, red no, purple uncertain. const QUICK_REPLIES = [ { label: "Yes", bg: "#0D2B1A", color: "#4ADE80", border: "#1A4A2A" }, { label: "Mostly", bg: "#181A0D", color: "#C8D84A", border: "#343A1A" }, { label: "No", bg: "#2B0D0D", color: "#F87171", border: "#4A1A1A" }, { label: "Not sure", bg: "#14111E", color: "#9F8DF5", border: "#26203A" }, ]; // ─── R-A: RESPONDER STATUS ──────────────────────────────────────────────────── // One screen. One decision. Toggle and wait. function ResponderStatusScreen({ place, onAvailable, onBack }) { const [available, setAvailable] = useState(false); const pendingRef = useRef(null); // holds the incoming-request demo timeout function clearPending() { if (pendingRef.current) { clearTimeout(pendingRef.current); pendingRef.current = null; } } function toggle() { if (!available) { setAvailable(true); // Simulate an incoming question arriving after 2.8s. // Stored so it can be cancelled if the user toggles off before it fires. pendingRef.current = setTimeout(onAvailable, 2800); } else { setAvailable(false); clearPending(); // ← cancel the pending transition immediately } } // Cancel on unmount (e.g. user hits back while available) useEffect(() => () => clearPending(), []); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> {/* Slim top bar — just place identity */} <div style={{ padding: "18px 20px 16px", flexShrink: 0, display: "flex", alignItems: "center", gap: 12, }}> <button onClick={onBack} style={{ background: "none", border: "none", color: "#333345", fontSize: 18, cursor: "pointer", padding: "0 4px", lineHeight: 1, }}>←</button> <span style={{ fontSize: 20 }}>{place.emoji}</span> <div> <div style={{ fontSize: 15, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> {place.name} </div> <div style={{ display: "flex", alignItems: "center", gap: 5, marginTop: 2 }}> <LiveDot color={place.accent} size={6} /> <span style={{ fontSize: 11, color: place.accent, fontFamily: "'DM Mono', monospace" }}> {place.people} here now </span> </div> </div> </div> {/* Main area — vertically centered, nothing extra */} <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "0 28px 60px", }}> {/* Toggle — the whole point of the screen */} <div onClick={toggle} style={{ width: "100%", padding: "24px 22px", background: available ? place.accent + "10" : "#13131A", border: 1.5px solid ${available ? place.accent + "55" : "#1E1E2A"}, borderRadius: 22, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "space-between", transition: "all 0.25s", marginBottom: 20, }} > <div> <div style={{ fontSize: 16, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", marginBottom: 4, }}> {available ? "Available to help" : "Available to help"} </div> <div style={{ fontSize: 12, color: available ? place.accent : "#333345", fontFamily: "'DM Mono', monospace" }}> {available ? "Listening for questions…" : "Travelers nearby can't reach you yet"} </div> </div> {/* Toggle pill */} <div style={{ width: 50, height: 28, borderRadius: 14, flexShrink: 0, background: available ? place.accent : "#1E1E2A", border: 2px solid ${available ? place.accent : "#2A2A38"}, position: "relative", transition: "all 0.25s", }}> <div style={{ position: "absolute", top: 3, left: available ? 23 : 3, width: 18, height: 18, borderRadius: "50%", background: "#fff", transition: "left 0.25s", boxShadow: "0 1px 4px rgba(0,0,0,0.3)", }} /> </div> </div> {/* Three lines. No more. */} <div style={{ display: "flex", flexDirection: "column", gap: 10, width: "100%" }}> {[ "Questions expire automatically.", "You can ignore any request.", "Answering takes under 10 seconds.", ].map((line, i) => ( <div key={i} style={{ fontSize: 12, color: "#333345", fontFamily: "'DM Mono', monospace", lineHeight: 1.5, display: "flex", gap: 8, }}> <span style={{ color: "#222230" }}>—</span> {line} </div> ))} </div> {/* Reciprocity — primary line + one light human touch beneath it */} <div style={{ marginTop: 36, textAlign: "center", display: "flex", flexDirection: "column", gap: 6, }}> <div style={{ fontSize: 12, color: "#2A2A3A", fontFamily: "'DM Mono', monospace" }}> Help from where you are. Get help where you're going. </div> <div style={{ fontSize: 11, color: "#1E1E28", fontFamily: "'DM Mono', monospace" }}> Don't underestimate karma :) </div> </div> </div> </div> ); } // ─── R-B: INCOMING REQUEST ──────────────────────────────────────────────────── // The question is the hero. Quick replies are the floor. // Type and photo expand INLINE — no new screen, no navigation. function IncomingRequestScreen({ place, onQuickReply, onTypeReply, onSendPhoto, onDismiss }) { const [req] = useState(() => INCOMING_REQUESTS[Math.floor(Math.random() * INCOMING_REQUESTS.length)]); const [age, setAge] = useState(8); const [mode, setMode] = useState("default"); // default | typing const [typedText, setTypedText] = useState(""); const textRef = useRef(null); useEffect(() => { const t = setInterval(() => setAge(a => a + 1), 1000); return () => clearInterval(t); }, []); useEffect(() => { if (mode === "typing" && textRef.current) textRef.current.focus(); }, [mode]); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> {/* Minimal top — place + age, no chrome */} <div style={{ padding: "16px 20px 12px", flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: "1px solid #18181F", }}> <div style={{ display: "flex", alignItems: "center", gap: 7 }}> <LiveDot color={place.accent} size={6} /> <span style={{ fontSize: 12, color: place.accent, fontFamily: "'DM Mono', monospace", fontWeight: 600 }}> {place.name} </span> </div> <span style={{ fontSize: 11, color: "#2A2A3A", fontFamily: "'DM Mono', monospace" }}> {age < 60 ? ${age}s : ${Math.floor(age / 60)}m} ago </span> </div> {/* Question — takes up natural space, large and clear */} <div style={{ padding: "28px 22px 20px", flexShrink: 0 }}> <div style={{ fontSize: 11, color: "#333345", fontFamily: "'DM Mono', monospace", marginBottom: 12 }}> {req.context} </div> <div style={{ fontSize: 20, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif", lineHeight: 1.3, }}> {req.q} </div> </div> {/* Inline type expansion */} {mode === "typing" && ( <div style={{ padding: "0 22px 16px", animation: "fadein 0.2s ease" }}> <textarea ref={textRef} value={typedText} onChange={e => setTypedText(e.target.value)} placeholder="What do you see right now?" rows={3} maxLength={160} style={{ width: "100%", background: "#13131A", border: 1.5px solid ${place.accent}44, borderRadius: 14, padding: "12px 14px", color: "#F0EDE8", fontSize: 14, fontFamily: "'DM Sans', sans-serif", outline: "none", resize: "none", lineHeight: 1.5, caretColor: place.accent, boxSizing: "border-box", }} /> <div style={{ display: "flex", gap: 8, marginTop: 8 }}> <button onClick={() => typedText.trim() && onTypeReply(typedText.trim(), req.q)} disabled={!typedText.trim()} style={{ flex: 1, padding: "11px", background: typedText.trim() ? place.accent : "#1E1E2A", border: "none", borderRadius: 12, color: typedText.trim() ? "#0C0C0F" : "#333345", fontSize: 13, fontWeight: 700, fontFamily: "'DM Mono', monospace", cursor: typedText.trim() ? "pointer" : "default", }} >Send</button> <button onClick={() => { setMode("default"); setTypedText(""); }} style={{ padding: "11px 16px", background: "#13131A", border: "1px solid #22222F", borderRadius: 12, color: "#444456", fontSize: 13, fontFamily: "'DM Mono', monospace", cursor: "pointer", }} >Cancel</button> </div> </div> )} <div style={{ flex: 1 }} /> {/* Quick replies — primary, always visible, bottom of screen */} {mode === "default" && ( <div style={{ padding: "0 20px 8px", flexShrink: 0 }}> <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 8 }}> {QUICK_REPLIES.map(r => ( <button key={r.label} onClick={() => onQuickReply(r.label, req.q)} style={{ background: r.bg, border: 1px solid ${r.border}, borderRadius: 16, padding: "16px 10px", color: r.color, fontSize: 16, fontWeight: 700, fontFamily: "'DM Mono', monospace", cursor: "pointer", letterSpacing: "0.02em", }} onMouseEnter={e => { e.currentTarget.style.filter = "brightness(1.12)"; }} onMouseLeave={e => { e.currentTarget.style.filter = "none"; }} >{r.label}</button> ))} </div> {/* Secondary row — flat, unobtrusive, inline icons only */} <div style={{ display: "flex", gap: 6, marginBottom: 8 }}> <button onClick={() => setMode("typing")} style={{ flex: 1, padding: "11px 8px", background: "#0E0E14", border: "1px solid #1A1A24", borderRadius: 12, color: "#444456", fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, }} > <span style={{ fontSize: 14 }}>✏</span> Add detail </button> <button onClick={() => onSendPhoto(req.q)} style={{ flex: 1, padding: "11px 8px", background: "#0E0E14", border: "1px solid #1A1A24", borderRadius: 12, color: "#444456", fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, }} > <span style={{ fontSize: 14 }}>📷</span> Live photo </button> <button onClick={onDismiss} style={{ padding: "11px 14px", background: "#0E0E14", border: "1px solid #1A1A24", borderRadius: 12, color: "#2A2A3A", fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer", }} >Skip</button> </div> </div> )} {/* When typing — minimal footer */} {mode === "typing" && ( <div style={{ padding: "0 20px 20px", flexShrink: 0 }}> <button onClick={onDismiss} style={{ width: "100%", padding: "11px", background: "none", border: "none", color: "#222230", fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}>Skip this question</button> </div> )} </div> ); } // ─── R-C: LIVE PHOTO SCREEN ─────────────────────────────────────────────────── // Immediate. No header. Tap once to capture, tap once to send. // The photo is the whole screen. function PhotoSendScreen({ place, question, onSend, onBack }) { const [phase, setPhase] = useState("ready"); // ready | capturing | captured useEffect(() => { if (phase === "capturing") { setTimeout(() => setPhase("captured"), 900); } }, [phase]); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> {/* Photo fills the top half — no header, no labels */} <div style={{ position: "relative", flexShrink: 0 }}> <LivePhoto place={place} /> {/* Flash overlay on capture */} {phase === "capturing" && ( <div style={{ position: "absolute", inset: 0, background: "rgba(255,255,255,0.2)", animation: "fadein 0.08s ease", pointerEvents: "none", }} /> )} {/* Captured: accent frame */} {phase === "captured" && ( <div style={{ position: "absolute", inset: 0, border: 3px solid ${place.accent}, pointerEvents: "none", animation: "fadein 0.15s ease", }} /> )} {/* Back — small, top-left, always present */} <button onClick={onBack} style={{ position: "absolute", top: 12, left: 12, background: "rgba(0,0,0,0.5)", border: "none", borderRadius: 10, padding: "5px 10px", color: "rgba(255,255,255,0.6)", fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer", }}>←</button> </div> {/* Question context — small, underneath photo */} <div style={{ padding: "14px 20px 12px", flexShrink: 0 }}> <div style={{ fontSize: 12, color: "#333345", fontFamily: "'DM Mono', monospace", fontStyle: "italic" }}> Re: {question} </div> </div> <div style={{ flex: 1 }} /> {/* Single action button — changes state */} <div style={{ padding: "0 20px 28px", flexShrink: 0 }}> {phase === "ready" && ( <button onClick={() => setPhase("capturing")} style={{ width: "100%", padding: "16px", background: place.accent, border: "none", borderRadius: 16, color: "#0C0C0F", fontSize: 15, fontWeight: 700, fontFamily: "'Fraunces', serif", cursor: "pointer", }}>📷 Capture &amp; send</button> )} {phase === "capturing" && ( <div style={{ width: "100%", padding: "16px", borderRadius: 16, background: "#1E1E2A", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, }}> {[0, 0.15, 0.3].map((d, i) => ( <span key={i} style={{ width: 7, height: 7, borderRadius: "50%", background: place.accent + "88", display: "inline-block", animation: typingdot 1.1s ease-in-out ${d}s infinite, }} /> ))} </div> )} {phase === "captured" && ( <button onClick={onSend} style={{ width: "100%", padding: "16px", background: place.accent, border: "none", borderRadius: 16, color: "#0C0C0F", fontSize: 15, fontWeight: 700, fontFamily: "'Fraunces', serif", cursor: "pointer", animation: "fadein 0.2s ease", }}>Send photo →</button> )} </div> </div> ); } // ─── R-D: SENT CONFIRMATION ─────────────────────────────────────────────────── // Two lines. Auto-returns after 3.2s. No reward theater. // replyLabel: "Yes" | "Mostly" | "No" | "Not sure" | "Custom reply" | "Live photo" function SentConfirmationScreen({ place, replyType, replyLabel, onDone }) { const subtext = { quick: "You helped a traveler decide.", typed: "Your reply is on its way.", photo: "They can see what you're seeing.", }; useEffect(() => { const t = setTimeout(onDone, 3200); return () => clearTimeout(t); }, []); return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F", alignItems: "center", justifyContent: "center", padding: "40px 32px", }}> {/* Single pulse ring */} <div style={{ position: "relative", width: 64, height: 64, marginBottom: 28 }}> <div style={{ position: "absolute", inset: 0, borderRadius: "50%", border: 1.5px solid ${place.accent}, opacity: 0, animation: "ring-out 1.8s ease-out 0s infinite", }} /> <div style={{ position: "absolute", inset: "18%", borderRadius: "50%", background: place.accent + "14", border: 1.5px solid ${place.accent}44, display: "flex", alignItems: "center", justifyContent: "center", color: place.accent, fontSize: 18, fontWeight: 700, }}>✓</div> </div> {/* What was sent — the actual reply label, large and clear */} <div style={{ fontSize: 11, color: "#333345", fontFamily: "'DM Mono', monospace", letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 6, }}>Sent</div> <div style={{ fontSize: 26, fontWeight: 700, color: place.accent, fontFamily: "'Fraunces', serif", marginBottom: 20, textAlign: "center", }}>{replyLabel || "Reply"}</div> <div style={{ fontSize: 12, color: "#444456", fontFamily: "'DM Mono', monospace", textAlign: "center", }}>{subtext[replyType] || subtext.quick}</div> {/* Auto-dismiss progress bar */} <div style={{ marginTop: 36, width: 40, height: 2, background: "#1E1E2A", borderRadius: 2, overflow: "hidden", }}> <div style={{ height: "100%", background: place.accent + "55", animation: "progress-fill 3.2s linear forwards", borderRadius: 2, }} /> </div> </div> ); } // ─── RESPONDER PLACE PICKER ──────────────────────────────────────────────────── // Shown when the responder hasn't selected a place yet. // Reuses the same place card style as PlaceListScreen — no new design language. function ResponderPlacePickerScreen({ onSelect, onBack }) { return ( <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "#0C0C0F" }}> <div style={{ padding: "22px 20px 14px", flexShrink: 0 }}> <button onClick={onBack} style={{ background: "none", border: "none", color: "#333345", fontSize: 18, cursor: "pointer", padding: "0 4px", marginBottom: 16, }}>←</button> <div style={{ fontSize: 18, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> Which place are you at? </div> <div style={{ fontSize: 12, color: "#333345", fontFamily: "'DM Mono', monospace", marginTop: 4 }}> Select where you are right now. </div> </div> <div style={{ flex: 1, overflowY: "auto", padding: "8px 20px 24px", display: "flex", flexDirection: "column", gap: 10 }}> {PLACES.map((place, i) => ( <button key={place.id} onClick={() => onSelect(place)} style={{ background: place.gradient, border: "1px solid rgba(255,255,255,0.07)", borderRadius: 18, padding: "16px 18px", cursor: "pointer", textAlign: "left", animation: fadein 0.25s ease ${i * 0.06}s both, display: "flex", alignItems: "center", justifyContent: "space-between", }}> <div style={{ display: "flex", alignItems: "center", gap: 12 }}> <span style={{ fontSize: 22 }}>{place.emoji}</span> <div> <div style={{ fontSize: 15, fontWeight: 700, color: "#F0EDE8", fontFamily: "'Fraunces', serif" }}> {place.name} </div> <div style={{ fontSize: 11, color: "rgba(240,237,232,0.5)", fontFamily: "'DM Mono', monospace", marginTop: 2 }}> {place.area} </div> </div> </div> <div style={{ display: "flex", alignItems: "center", gap: 5 }}> <LiveDot color={place.accent} size={6} /> <span style={{ fontSize: 11, color: place.accent, fontFamily: "'DM Mono', monospace" }}> {place.people} here </span> </div> </button> ))} </div> </div> ); } // ─── ROOT ───────────────────────────────────────────────────────────────────── export default function App() { const [screen, setScreen] = useState("list"); const [selectedPlace, setSelectedPlace] = useState(null); const [question, setQuestion] = useState(""); const [responder, setResponder] = useState(null); const [reply, setReply] = useState(""); const [withPhoto, setWithPhoto] = useState(false); // Responder-side state const [responderPlace, setResponderPlace] = useState(null); // null until picker used const [responderQuestion, setResponderQuestion] = useState(""); const [sentReplyType, setSentReplyType] = useState("quick"); const [sentReplyLabel, setSentReplyLabel] = useState(""); function selectPlace(place) { setSelectedPlace(place); setScreen("detail"); } function startAsk(prefill) { setQuestion(prefill || ""); setScreen("ask"); } function sendQuestion(q) { setQuestion(q); setScreen("waiting"); } function receiveReply(r, text, photo) { setResponder(r); setReply(text); setWithPhoto(!!photo); setScreen("chat"); } function noAnswer() { setScreen("noanswer"); } function reset() { setSelectedPlace(null); setQuestion(""); setResponder(null); setReply(""); setWithPhoto(false); setScreen("list"); } // Responder helpers function enterResponder(place) { // If a specific place was passed (per-card), use it directly. // If null (footer link), go to picker first. if (place) { setResponderPlace(place); setScreen("r-status"); } else { setScreen("r-pick"); } } function selectResponderPlace(place) { setResponderPlace(place); setScreen("r-status"); } function onAvailable() { setScreen("r-incoming"); } function onQuickReply(label, q) { setResponderQuestion(q); setSentReplyType("quick"); setSentReplyLabel(label); // "Yes" / "Mostly" / "No" / "Not sure" setScreen("r-sent"); } // onTypeReply receives (text, q) — inline editing, no separate screen function onTypeReply(text, q) { setResponderQuestion(q); setSentReplyType("typed"); setSentReplyLabel("Custom reply"); setScreen("r-sent"); } function onSendPhoto(q) { setResponderQuestion(q); setScreen("r-photo"); } function onReplySent(type) { setSentReplyType(type); setSentReplyLabel("Live photo"); setScreen("r-sent"); } function onResponderDone() { setScreen("list"); } return ( <div style={{ minHeight: "100vh", background: "#06060A", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'DM Sans', sans-serif", padding: 20, }}> <style>{ @import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,wght@0,600;0,700;1,400;1,600&family=DM+Sans:wght@400;500;600&family=DM+Mono:wght@400;500&display=swap'); * { box-sizing: border-box; margin: 0; padding: 0; } ::-webkit-scrollbar { width: 3px; } ::-webkit-scrollbar-thumb { background: #2A2A38; border-radius: 4px; } @keyframes livepulse { 0%,100% { opacity: 1; } 50% { opacity: 0.5; } } @keyframes ring-out { 0% { transform: scale(0.6); opacity: 0.7; } 100% { transform: scale(1.4); opacity: 0; } } @keyframes fadein { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } } @keyframes typingdot { 0%,100% { opacity: 0.3; transform: translateY(0); } 50% { opacity: 1; transform: translateY(-3px); } } @keyframes progress-fill { from { width: 0%; } to { width: 100%; } } button { transition: all 0.15s; } button:active { transform: scale(0.97) !important; } }</style> <div style={{ position: "fixed", top: 26, left: 0, right: 0, textAlign: "center", zIndex: 10, pointerEvents: "none", }}> <span style={{ fontSize: 19, fontFamily: "'Fraunces', serif", fontWeight: 700, color: "rgba(240,237,232,0.5)", letterSpacing: "0.01em", }}>instantip</span> </div> <div style={{ width: "100%", maxWidth: 390, background: "#0C0C0F", borderRadius: 32, overflow: "hidden", boxShadow: "0 40px 100px rgba(0,0,0,0.7), 0 0 0 1px rgba(255,255,255,0.04)", height: 720, display: "flex", flexDirection: "column", }}> {/* Asker flow */} {screen === "list" && <PlaceListScreen onSelect={selectPlace} onIAmHere={enterResponder} />} {screen === "detail" && <PlaceDetailScreen place={selectedPlace} onAsk={startAsk} onBack={() => setScreen("list")} />} {screen === "ask" && <AskScreen place={selectedPlace} prefill={question} onSend={sendQuestion} onBack={() => setScreen("detail")} />} {screen === "waiting" && <WaitingScreen place={selectedPlace} question={question} onReply={receiveReply} onNoAnswer={noAnswer} />} {screen === "noanswer" && <NoAnswerScreen place={selectedPlace} question={question} onRetry={() => setScreen("ask")} onLeave={reset} />} {screen === "chat" && <ChatScreen place={selectedPlace} question={question} responder={responder} initialReply={reply} withPhoto={withPhoto} onDone={reset} />} {/* Responder flow */} {screen === "r-pick" && <ResponderPlacePickerScreen onSelect={selectResponderPlace} onBack={() => setScreen("list")} />} {screen === "r-status" && <ResponderStatusScreen place={responderPlace} onAvailable={onAvailable} onBack={() => setScreen("list")} />} {screen === "r-incoming" && <IncomingRequestScreen place={responderPlace} onQuickReply={onQuickReply} onTypeReply={onTypeReply} onSendPhoto={onSendPhoto} onDismiss={onResponderDone} />} {screen === "r-photo" && <PhotoSendScreen place={responderPlace} question={responderQuestion} onSend={() => onReplySent("photo")} onBack={() => setScreen("r-incoming")} />} {screen === "r-sent" && <SentConfirmationScreen place={responderPlace} replyType={sentReplyType} replyLabel={sentReplyLabel} onDone={onResponderDone} />} </div> </div> ); } import { StrictMode } from 'react' import { createRoot } from 'react-dom/client' import App from './App.jsx' createRoot(document.getElementById('root')).render( <StrictMode> <App /> </StrictMode> )
